diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
index 9a16ca96db76..a43df467082b 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
@@ -983,6 +983,19 @@ Instruction *InstCombinerImpl::foldAddWithConstant(BinaryOperator &Add) {
     }
   }

+  // Fold (add (zext nneg (add nsw X, C1)), C2) -> add (sext X), C1 + C2
+  // When the zext has the nneg flag, it can be regarded as sext.
+  const APInt *C1;
+  if (match(Op0, m_ZExt(m_NSWAdd(m_Value(X), m_APInt(C1))))) {
+    if (auto *PNNI = dyn_cast<PossiblyNonNegInst>(Op0);
+        PNNI && PNNI->hasNonNeg()) {
+      // Create sext X and add the combined constant.
+      Value *Sext = Builder.CreateSExt(X, Ty);
+      APInt CombinedC = C1->zext(Ty->getScalarSizeInBits()) + *C;
+      return BinaryOperator::CreateAdd(Sext, ConstantInt::get(Ty, CombinedC));
+    }
+  }
+
   // Fold (add (zext (add X, -1)), 1) -> (zext X) if X is non-zero.
   // TODO: There's a general form for any constant on the outer add.
   if (C->isOne()) {

log.source_program:
define i32 @fold_zext_nneg_add_const(i8 %x) {
  %xx = add nsw i8 %x, 123
  %ze = zext nneg i8 %xx to i32
  %r = add nsw i32 %ze, -25
  ret i32 %r
}

